base='http://localhost:80'
paths = [
    '/__debugger__', '/?__debugger__=yes', '/?__debugger__=yes&cmd=resource&f=style.css',
    '/debug', '/_debug', '/_debugger', '/_console', '/shell', '/python', '/eval', '/execute',
    '/traceback', '/exceptions', '/error', '/raise', '/whoami', '/version', '/about', '/info', '/config', '/environment', '/system',
    '/source', '/src', '/code', '/app', '/console', '/dashboard', '/login', '/logout', '/admin', '/manage', '/manage/console', '/manage/login'
]
for p in paths:
    url = base + p
    try:
        with urllib.request.urlopen(url, timeout=5) as r:
            print(p, r.getcode(), r.getheader('Content-Type',''), len(r.read()))
    except urllib.error.HTTPError as e:
        if e.code != 404:
            print('HTTP', p, e.code, e.headers.get('Content-Type',''))
    except Exception as e:
        print('ERR', p, e)
